import{_ as a,o as i,c as o,a0 as n}from"./chunks/framework.BjpW4enL.js";const g=JSON.parse('{"title":"ADR-0027: Gemini Integration via AgentGateway como LLM Provider","description":"","frontmatter":{},"headers":[],"relativePath":"20_Arquitetura/adr/0027-gemini-integration-agentgateway.md","filePath":"20_Arquitetura/adr/0027-gemini-integration-agentgateway.md","lastUpdated":1783623176000}'),t={name:"20_Arquitetura/adr/0027-gemini-integration-agentgateway.md"};function s(l,e,r,d,c,p){return i(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="adr-0027-gemini-integration-via-agentgateway-como-llm-provider" tabindex="-1">ADR-0027: Gemini Integration via AgentGateway como LLM Provider <a class="header-anchor" href="#adr-0027-gemini-integration-via-agentgateway-como-llm-provider" aria-label="Permalink to &quot;ADR-0027: Gemini Integration via AgentGateway como LLM Provider&quot;">​</a></h1><p><strong>Status</strong>: Aceito<br><strong>Date</strong>: 2026-06-27<br><strong>Deciders</strong>: @ops</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>O NEXUS utiliza o Ollama local (<code>qwen2.5-coder:nexus</code>) como modelo de enriquecimento semântico L2 e o modelo <code>deepseek-v4-flash</code> via OpenRouter como juiz de avaliação de alucinação (eval.py). Ambos têm limitações:</p><ul><li><strong>Ollama 1.5B</strong>: Performance inferior para raciocínio complexo, ideal apenas para tarefas de baixa exigência cognitiva (embedding, chunking)</li><li><strong>DeepSeek via OpenRouter</strong>: Sujeito a rate limiting do free tier (&quot;Model busy&quot;), sem fallback automático configurado</li></ul><p>O Google Gemini (<code>gemini-2.5-flash</code>) oferece um modelo gratuito competitivo com DeepSeek, com capacidade de raciocínio superior ao Ollama 1.5B. A API Gemini suporta formato OpenAI-compatible via endpoint <code>https://generativelanguage.googleapis.com/v1beta/openai</code> e também provider nativo via <code>apiKey</code>.</p><p>O AgentGateway (já adotado no ADR-0004) pode ser configurado como proxy para Gemini, unificando o ponto de acesso para todos os LLMs do ecossistema.</p><h2 id="decision-drivers" tabindex="-1">Decision Drivers <a class="header-anchor" href="#decision-drivers" aria-label="Permalink to &quot;Decision Drivers&quot;">​</a></h2><ul><li><strong>Unificar acesso LLM</strong>: Um único endpoint (AgentGateway) para todos os providers, em vez de URLs diferentes para cada modelo</li><li><strong>Provider nativo</strong>: Usar <code>provider: gemini</code> do AgentGateway em vez do workaround OpenAI-compatible, para aproveitar tratamento nativo de auth</li><li><strong>Juiz independente</strong>: Gemini como juiz de alucinação L2, substituindo o modelo local que pode ter viés de confirmação</li><li><strong>Compatibilidade com eval.py</strong>: eval.py precisa suportar dual-mode (Ollama nativo e OpenAI-compatible) para funcionar com AgentGateway</li><li><strong>Resiliência a rate limit</strong>: Tratamento de HTTP 429 com backoff longo (65s) para o free tier Gemini</li></ul><h2 id="considered-options" tabindex="-1">Considered Options <a class="header-anchor" href="#considered-options" aria-label="Permalink to &quot;Considered Options&quot;">​</a></h2><h3 id="option-1-agentgateway-com-provider-gemini-escolhido" tabindex="-1">Option 1: AgentGateway com <code>provider: gemini</code> (escolhido) <a class="header-anchor" href="#option-1-agentgateway-com-provider-gemini-escolhido" aria-label="Permalink to &quot;Option 1: AgentGateway com \`provider: gemini\` (escolhido)&quot;">​</a></h3><p>Proxy AgentGateway configuração nativa Gemini.</p><p><strong>Pros</strong>:</p><ul><li>Provider nativo, sem necessidade de URL de override</li><li>Suporte a CORS, logging, e policies via AgentGateway</li><li>Container separado, baixo overhead (64MB RAM)</li><li>Ponto de acesso unificado (<code>:8080/v1/chat/completions</code>)</li><li>Compatível com o stack existente (Docker Compose)</li></ul><p><strong>Cons</strong>:</p><ul><li>Container extra no stack</li><li>Config YAML adicional para manter (config.gemini.yaml)</li><li>Latência adicional de ~1-5ms do proxy</li></ul><h3 id="option-2-openai-compatible-direto" tabindex="-1">Option 2: OpenAI-compatible direto <a class="header-anchor" href="#option-2-openai-compatible-direto" aria-label="Permalink to &quot;Option 2: OpenAI-compatible direto&quot;">​</a></h3><p>OpenCode consome Gemini via endpoint OpenAI-compatible sem proxy.</p><p><strong>Pros</strong>:</p><ul><li>Zero infraestrutura adicional</li><li>Mais simples (só configurar a URL)</li></ul><p><strong>Cons</strong>:</p><ul><li>Sem logging centralizado</li><li>Sem policies de CORS/rate limit</li><li>Sem ponto de unificação para múltiplos providers</li><li>Cada serviço precisa configurar sua própria URL</li></ul><h3 id="option-3-sdk-google-genai-diretamente-no-eval-py" tabindex="-1">Option 3: SDK Google GenAI diretamente no eval.py <a class="header-anchor" href="#option-3-sdk-google-genai-diretamente-no-eval-py" aria-label="Permalink to &quot;Option 3: SDK Google GenAI diretamente no eval.py&quot;">​</a></h3><p>eval.py usa biblioteca <code>google-genai</code> para chamar Gemini.</p><p><strong>Pros</strong>:</p><ul><li>Acesso a features específicas Gemini (safety settings, etc)</li><li>Sem dependência de proxy</li></ul><p><strong>Cons</strong>:</p><ul><li>Acopla eval.py a um SDK específico</li><li>eval.py precisaria de dois modos de chamada (Ollama + Google)</li><li>Sem os benefícios de proxy do AgentGateway</li><li>Duplica lógica de autenticação</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Adotar <strong>Option 1</strong>: AgentGateway com <code>provider: openai</code> delegando o rodízio de chaves para o <strong>KeyRotator</strong> (Porta 8090) com chaves do Gemini.</p><h3 id="configuracao-atualizada-feature-50" tabindex="-1">Configuração Atualizada (Feature 50) <a class="header-anchor" href="#configuracao-atualizada-feature-50" aria-label="Permalink to &quot;Configuração Atualizada (Feature 50)&quot;">​</a></h3><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># docker/agentgateway/config.gemini.yaml</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">llm</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8091</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  models</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;*&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      provider</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gemini</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      params</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        model</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gemini-2.5-flash</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        apiKey</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$GEMINI_API_KEY&quot;</span></span></code></pre></div><p>O container é exposto em duas portas dependendo do compose file:</p><ul><li><code>compose.yaml</code>: porta <code>8080 → 8091</code> (serviço <code>agentgateway</code>)</li><li><code>docker-compose.standalone.yml</code>: porta <code>8091</code> (serviço <code>gateway</code>)</li></ul><h3 id="eval-py-dual-mode" tabindex="-1">eval.py Dual-Mode <a class="header-anchor" href="#eval-py-dual-mode" aria-label="Permalink to &quot;eval.py Dual-Mode&quot;">​</a></h3><p>O <code>call_judge()</code> no eval.py detecta automaticamente o backend:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ollama nativo: OLLAMA_URL=http://localhost:11434</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → POST /api/chat com formato Ollama</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># OpenAI-compatible: OLLAMA_URL=http://localhost:8080/v1</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → POST /v1/chat/completions com formato OpenAI</span></span></code></pre></div><p>Rate limit handling: HTTP 429 do Gemini free tier → espera 65s + retry. Delay entre chamadas: 1s (OpenAI) / 0.5s (Ollama).</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Ponto de acesso unificado para todos os LLMs do ecossistema</li><li>Provider Gemini nativo no AgentGateway (sem workaround)</li><li>eval.py com suporte a dual-mode (Ollama + OpenAI-compatible)</li><li>Tratamento robusto de rate limit (429)</li><li>Infraestrutura de proxy já estabelecida (ADR-0004)</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>Container extra com consumo de 64MB RAM</li><li>Latência adicional de ~1-5ms do proxy</li><li>Duas configurações YAML para manter (config.yaml legado + config.gemini.yaml)</li></ul><h3 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h3><ul><li>API key free tier tem limite de 20 req/min → pode bloquear eval com muitos pares. Mitigação: backoff de 65s em 429, delay de 1s entre chamadas</li><li>A chave Firebase usada pode ter Gemini API desabilitada em qualquer momento. Mitigação: usar API key dedicada do Google AI Studio</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation Notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation Notes&quot;">​</a></h2><ul><li><code>GEMINI_API_KEY</code> no <code>.env</code> (placeholder ou chave real)</li><li><code>config.gemini.yaml</code> é o config ativo no <code>compose.yaml</code></li><li><code>config.yaml</code> legado (OpenRouter) também atualizado para Gemini</li><li><code>docker-compose.standalone.yml</code> mantém serviço <code>gateway</code> separado</li><li>Planos de integração: <code>gemini-opencode-integration.md</code></li></ul><h2 id="related-decisions" tabindex="-1">Related Decisions <a class="header-anchor" href="#related-decisions" aria-label="Permalink to &quot;Related Decisions&quot;">​</a></h2><ul><li><strong>ADR-0004</strong>: AgentGateway como Proxy LLM — decisão base que este ADR estende</li><li><strong>ADR-0026</strong>: L2 Enrichment — avaliação de alucinação que motivou o juiz externo</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://agentgateway.dev/docs/standalone/latest/llm/providers/gemini.md" target="_blank" rel="noreferrer">AgentGateway Gemini Provider Docs</a></li><li><a href="https://ai.google.dev/gemini-api/docs/openai" target="_blank" rel="noreferrer">Gemini API OpenAI-compatible</a></li><li><code>docker/agentgateway/config.gemini.yaml</code> — config ativa</li><li><code>docker/agentgateway/config.yaml</code> — config legado (atualizado)</li><li><code>workspace/experiments/hallucination-eval/eval.py</code> — dual-mode judge</li></ul>`,51)])])}const h=a(t,[["render",s]]);export{g as __pageData,h as default};
